SELECT SUM(pancreatic_incidence) AS total_pancreatic_incidence
FROM incidences
WHERE region_id = 0;

SELECT pancreatic_incidence AS total_incidence
FROM incidences
WHERE year = 2023;

SELECT AVG(pancreatic_incidence) AS avg_pancreatic_incidence
FROM incidences
WHERE year = 2023;

SELECT SUM(pancreatic_mortality) AS total_pancreatic_mortality, SUM(all_mortality) AS total_cancer_mortality
FROM mortalities
WHERE year = 2023;
